const input = $input.all().map(i => i.json);

function cleanText(value) {
  if (value === null || value === undefined) return "";
  return String(value)
    .replace(/\u00A0/g, " ")
    .replace(/[\u200B-\u200D\uFEFF]/g, "")
    .trim();
}

function normalizeBool(value, defaultValue = false) {
  if (value === null || value === undefined || value === "") return defaultValue;

  const v = String(value)
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  if (["sim", "s", "true", "1", "yes", "y"].includes(v)) return true;
  if (["nao", "n", "false", "0", "no"].includes(v)) return false;

  return defaultValue;
}

function normalizeTipo(value) {
  const v = cleanText(value).toLowerCase();

  if (["canonica", "canônica", "canonico", "canônico"].includes(v)) return "canonica";
  if (["alias", "apelido", "popular", "variante"].includes(v)) return "alias";

  return "alias";
}

function normalizePorte(value) {
  const v = cleanText(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  const allowed = new Set(["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"]);

  if (v === "médio") return "medio";
  if (v === "nao definido") return "nao_definido";
  if (v === "não definido") return "nao_definido";
  if (v === "indefinido") return "nao_definido";
  if (v === "") return "nao_definido";

  return allowed.has(v) ? v : "nao_definido";
}

function buildRow(row) {
  const nomeDigitado = cleanText(row.nome_digitado);
  const canonica = cleanText(row.nome_raca_canonica);

  if (!nomeDigitado || !canonica) return null;

  return {
    nome_digitado: nomeDigitado,
    nome_raca_canonica: canonica,
    tipo_registro: normalizeTipo(row.tipo_registro),
    porte_classificado: normalizePorte(row.porte_classificado),
    aceita_auauzin: normalizeBool(row.aceita_auauzin, false),
    potencial_dano: normalizeBool(row.potencial_dano, false),
    observacoes: cleanText(row.observacoes),
    ativo: normalizeBool(row.ativo, true),
  };
}

const rows = input
  .map(buildRow)
  .filter(Boolean);

const extrasSRD = [
  "SRD",
  "srd",
  "sem raça definida",
  "sem raca definida",
  "sem-raça-definida",
  "sem-raca-definida",
  "vira lata",
  "vira-lata",
  "viralata",
  "vira latinha",
  "vira-latinha",
  "mestiço",
  "mestico",
  "cão mestiço",
  "cao mestico",
  "cachorro mestiço",
  "cachorro mestico",
  "raça mista",
  "raca mista",
  "misto",
  "misturado",
  "cão misturado",
  "cao misturado",
  "cachorro misturado",
  "mixed breed",
];

for (const nome of extrasSRD) {
  rows.push({
    nome_digitado: nome,
    nome_raca_canonica: "SRD",
    tipo_registro: nome.toLowerCase() === "srd" ? "canonica" : "alias",
    porte_classificado: "nao_definido",
    aceita_auauzin: false,
    potencial_dano: false,
    observacoes: "alias operacional de SRD/vira-lata/raça mista; confirmar porte individualmente",
    ativo: true,
  });
}

// Remove duplicados por nome_digitado.
// Se houver duplicidade, a última linha vence.
const map = new Map();

for (const row of rows) {
  map.set(row.nome_digitado, row);
}

const finalRows = Array.from(map.values());

return [
  {
    json: {
      total_linhas_recebidas: input.length,
      total_linhas_normalizadas: finalRows.length,
      rows: finalRows,
    },
  },
];
